head.script:
scwin.preRowPos = 0;
scwin.statusFlag = "";
scwin.ctrtNoRowCount = 0;
scwin.tabIndex = "";
scwin.olddata = "";
scwin.flag = true;

scwin.onpageload = function () {
    scwin.f_DefaultValue();
};

scwin.onUdcCompleted = function () {
    btnLoading.hide();
    btnDischarge.hide();

    scwin.f_Set("INIT");

    cnd_ed_cust.focus();
};

//-------------------------------------------------------------------------
// function	name : f_initSetTab
// function	desc : Tab 초기화
//-------------------------------------------------------------------------
scwin.f_initSetTab = function () {
    tr_tab_center.setDisabled(false);
    tr_tab_center.setSelectedTabIndex(0);
};

//-------------------------------------------------------------------------
// function	name : f_selectTabMenu
// function	desc : Tab Menu 선택시 처리
//-------------------------------------------------------------------------
scwin.f_selectTabMenu = function (idx) {
    switch (idx) {
        case 0: //Main tab
            scwin.tabIndex = "TM";
            break;
        case 1: //Other tab
            scwin.tabIndex = "EX";
            break;
    }

    tr_tab_center.setSelectedTabIndex(idx);
};

scwin.tr_tab_center_onchange = function (tabId, index, userTabId) {
    scwin.f_selectTabMenu(index);
};

scwin.f_DefaultValue = function () {
    scwin.f_initSetTab();
    scwin.f_selectTabMenu(0);
};

//-------------------------------------------------------------------------
// function	name :	f_Set(gubun)
// function	desc : BuportTon, object, component, field 등 화면 구성 setting
// gubun :	INIT(초기화), RETRIEVE(조회모드), UPDATE(수정모드),	COPY(복사모드)
//-------------------------------------------------------------------------
scwin.f_Set = function (gubun) {
    switch (gubun) {
        case "INIT":
            $c.gus.cfDisableBtnOnly([btn_addRow, btn_deleteRow, btn_undoRow, btn_deleteRowAll]);
            $c.gus.cfDisableBtnOnly([btn_save, btn_cancel]);
            $c.gus.cfEnableBtnOnly([btn_create]);
            $c.gus.cfDisableObjects([tb_DetailInfo]);
            scwin.statusFlag = "INIT";
            break;
        case "RETRIEVE":
            $c.gus.cfDisableBtnOnly([btn_addRow, btn_deleteRow, btn_undoRow, btn_deleteRowAll]);
            $c.gus.cfDisableBtnOnly([btn_save, btn_cancel]);
            $c.gus.cfEnableBtnOnly([btn_create]);
            scwin.statusFlag = "RETRIEVE";
            break;
        case "RETRIEVE_D":
            $c.gus.cfEnableBtnOnly([btn_addRow, btn_deleteRow, btn_undoRow, btn_deleteRowAll]);
            $c.gus.cfDisableBtnOnly([btn_cancel]);
            $c.gus.cfEnableBtnOnly([btn_save, btn_create]);
            $c.gus.cfDisableObjects([tb_DetailInfo]);
            scwin.statusFlag = "RETRIEVE_D";
            break;
        case "CREATE":
            $c.gus.cfDisableBtnOnly([btn_create, btn_save]);
            $c.gus.cfDisableBtnOnly([btn_addRow, btn_deleteRow, btn_undoRow, btn_deleteRowAll]);
            $c.gus.cfEnableBtnOnly([btn_cancel, btn_save]);
            $c.gus.cfEnableBtnOnly([btn_addRow, btn_deleteRow, btn_undoRow, btn_deleteRowAll]);
            $c.gus.cfEnableObjects([tb_DetailInfo]);
            scwin.statusFlag = "CREATE";
            break;
        case "UPDATE":
            break;
        case "SAVE":
            $c.gus.cfEnableBtnOnly([btn_save]);
            $c.gus.cfDisableObjects([tb_DetailInfo]);
            break;
        case "DELETE":
            scwin.statusFlag = "DELETE";
            break;
    }
};

//-------------------------------------------------------------------------
// function	name : f_FieldClear
// function	desc : 조회조건	초기화
//-------------------------------------------------------------------------
scwin.f_FieldClear = function () {
    $c.gus.cfInitObjects(tb_searchCondition, null);

    switch (scwin.tabIndex) {
        case "TM":
            ds_MasterList.setJSON([]);
            ds_DetailInfo.setJSON([]);
            totalRows2.setValue(ds_DetailInfo.getRowCount());
            break;
        case "EX":
            ds_TariffList.setJSON([]);
            totalRows3.setValue(ds_DetailInfo.getRowCount());
            break;
    }
};

//-------------------------------------------------------------------------
// function	name : f_Retrieve
// function	desc : 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
    let chk = await $c.gus.cfValidate(tb_searchCondition);

    if (!chk) {
        return;
    }

    if (!await $c.gus.cfIsAfterDate(cnd_ed_apdtFrom.getValue(), cnd_ed_apdtTo.getValue(), false)) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_039);
        return;
    }

    if (!await scwin.f_ReqFieldChk("SEARCH")) {
        return;
    }

    dma_SearchParam.setEmptyValue();

    dma_SearchParam.set("kcomcd", "DBEX");
    dma_SearchParam.set("blgb", "H");
    dma_SearchParam.set("cust", cnd_ed_cust.getValue());
    dma_SearchParam.set("liner", cnd_ed_liner.getValue());
    dma_SearchParam.set("portFrom", cnd_ed_portFrom.getValue());
    dma_SearchParam.set("portTo", cnd_ed_portTo.getValue());
    dma_SearchParam.set("apdtFrom", cnd_ed_apdtFrom.getValue());
    dma_SearchParam.set("apdtTo", cnd_ed_apdtTo.getValue());
    dma_SearchParam.set("contractno", cnd_ed_contractno.getValue());
    dma_SearchParam.set("triangle", cnd_chb_triangle.getValue());

    switch (scwin.tabIndex) {
        case "TM":
            dma_SearchParam.set("workgb", "LIST");

            ds_DetailInfo.setJSON([]);
            $c.sbm.execute(sbm_retrieve);
            break;
        case "EX":
            dma_SearchParam.set("workgb", "INFOLIST");

            ds_DetailInfo.setJSON([]);
            $c.sbm.execute(sbm_retrieve_list);
            break;
    }
};

//-------------------------------------------------------------------------
// function	name : f_DetailInfoRetrieve
// function	desc : 상세 정보 조회
//-------------------------------------------------------------------------
scwin.f_DetailInfoRetrieve = function (row) {
    let rowJson = ds_MasterList.getRowJSON(row);

    dma_SearchParam.setEmptyValue();
    ds_DetailInfo.setJSON([]);

    dma_SearchParam.set("kcomcd", rowJson.kcomcd);
    dma_SearchParam.set("blgb", "H");
    dma_SearchParam.set("cust", rowJson.cust);
    dma_SearchParam.set("liner", rowJson.liner);
    dma_SearchParam.set("portFrom", rowJson.portFrom);
    dma_SearchParam.set("portTo", rowJson.portTo);
    dma_SearchParam.set("apdtFrom", rowJson.apdtFrom);
    dma_SearchParam.set("apdtTo", rowJson.apdtTo);
    dma_SearchParam.set("contractno", rowJson.contractno);
    dma_SearchParam.set("workgb", "INFO");
    dma_SearchParam.set("dg", rowJson.dg);

    $c.sbm.execute(sbm_retrieve_info);
};

//-------------------------------------------------------------------------
// function	name : f_AddRow
// function	desc : 그리드 행 추가
//-------------------------------------------------------------------------
scwin.f_AddRow = function () {
    let row = ds_DetailInfo.insertRow();
    let prevRowJson = ds_DetailInfo.getRowJSON(row - 1);

    ds_DetailInfo.setRowPosition(row);

    ds_DetailInfo.setCellData(row, "Currow", row + 1);
    ds_DetailInfo.setCellData(row, "contractno", prevRowJson.contractno);
    ds_DetailInfo.setCellData(row, "contractnoTamp", prevRowJson.contractnoTamp);
    ds_DetailInfo.setCellData(row, "cust", prevRowJson.cust);
    ds_DetailInfo.setCellData(row, "custnm", prevRowJson.custnm);
    ds_DetailInfo.setCellData(row, "liner", prevRowJson.liner);
    ds_DetailInfo.setCellData(row, "linernm", prevRowJson.linernm);
    ds_DetailInfo.setCellData(row, "portFrom", prevRowJson.portFrom);
    ds_DetailInfo.setCellData(row, "portFromNm", prevRowJson.portFromNm);
    ds_DetailInfo.setCellData(row, "portTo", prevRowJson.portTo);
    ds_DetailInfo.setCellData(row, "portToNm", prevRowJson.portToNm);
    ds_DetailInfo.setCellData(row, "apdtFrom", prevRowJson.apdtFrom);
    ds_DetailInfo.setCellData(row, "apdtTo", prevRowJson.apdtTo);
    ds_DetailInfo.setCellData(row, "dg", "N");
    ds_DetailInfo.setCellData(row, "kcomcd", "DBEX");
    ds_DetailInfo.setCellData(row, "blgb", "H");
    ds_DetailInfo.setCellData(row, "curr", "USD");

    gr_DetailInfo.setFocusedCell(row, "item", true);

    if (ds_DetailInfo.getModifiedIndex().length > 0) {
        $c.gus.cfEnableBtnOnly([btn_save]);
    }

    scwin.f_ContractInfo();
};

//-------------------------------------------------------------------------
// function	name : f_DelRow
// function	desc : 그리드 행 삭제
//-------------------------------------------------------------------------
scwin.f_DelRow = function () {
    let rowPosition = ds_DetailInfo.getRowPosition();

    if (ds_DetailInfo.getRowStatus(rowPosition) == "C") {
        ds_DetailInfo.removeRow(rowPosition);
    } else {
        ds_DetailInfo.deleteRow(rowPosition);
        ds_DetailInfo.setRowPosition(rowPosition);       // 바인딩된 필드값 사라짐
    }

    if (ds_DetailInfo.getModifiedIndex().length > 0) {
        $c.gus.cfEnableBtnOnly([btn_save]);
    }
};

//-------------------------------------------------------------------------
// function	name : f_DelRow
// function	desc : 그리드 행 삭제
//-------------------------------------------------------------------------
scwin.f_DelRowAll = async function () {
    let chk = await $c.win.confirm("전체 삭제을 적용하시겠습니까?");

    if (chk) {
        for (let i = ds_DetailInfo.getRowCount() - 1; i >= 0; i--) {
            if (ds_DetailInfo.getRowStatus(i) == "C") {
                ds_DetailInfo.removeRow(i);
            } else {
                ds_DetailInfo.deleteRow(i);
            }
        }
    }

    if (ds_DetailInfo.getModifiedIndex().length > 0) {
        $c.gus.cfEnableBtnOnly([btn_save]);
    }
};

//-------------------------------------------------------------------------
// function	name : f_UndoRow
// function	desc : 그리드 행 취소
//-------------------------------------------------------------------------
scwin.f_UndoRow = function () {
    $c.data.undoRow(ds_DetailInfo);

    if (ds_DetailInfo.getModifiedIndex().length > 0) {
        $c.gus.cfEnableBtnOnly([btn_save]);
    }
};

//-------------------------------------------------------------------------
// function	name : f_Save
// function	desc : 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
    if (ds_DetailInfo.getModifiedIndex().length == 0) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_001, ["Container Selling Tariff"]);
        return false;
    }

    let rowCnt = ds_DetailInfo.getRowCount();

    for (let i = 0; i < rowCnt; i++) {
        let rowJson = ds_DetailInfo.getRowJSON(i);

        if (!await $c.gus.cfIsAfterDate(rowJson.apdtFrom, rowJson.apdtTo, false)) {
            await $c.gus.cfAlertMsg("[" + (i + 1) + "] Line Is" + E_MSG_CM_ERR_039);
            return;
        }
    }

    if (await scwin.f_ReqFieldChk("DEATAIL_SEARCH")) {
        let chk = await $c.win.confirm(E_MSG_CM_CRM_001);

        if (chk) {
            $c.sbm.execute(sbm_save);
        }
    }
};

//-------------------------------------------------------------------------
// function	name : f_Save_Ex
// function	desc : 저장
//-------------------------------------------------------------------------
scwin.f_Save_Ex = async function () {
    if (ds_TariffList.getModifiedIndex().length == 0) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_001, ["Container Selling Tariff"]);
        return false;
    }

    if (await scwin.f_ReqFieldChk("TARIFFLIST")) {
        let chk = await $c.win.confirm(E_MSG_CM_CRM_001);

        if (chk) {
            $c.sbm.execute(sbm_save_list);
        }
    }
};

//-------------------------------------------------------------------------
// function	name : f_Cancel
// function	desc : 취소
//-------------------------------------------------------------------------
scwin.f_Cancel = function () {
    $c.data.undoAll(ds_MasterList);
    $c.data.undoAll(ds_DetailInfo);

    scwin.f_Set("RETRIEVE");
};

scwin.f_Create = async function () {
    ds_DetailInfo.setJSON([]);
    ds_ctrtNo.setJSON([]);

    await scwin.f_AddRow();

    let row = ds_DetailInfo.getRowPosition();
    let mRow = ds_MasterList.getRowPosition();
    let rowJson = ds_MasterList.getRowJSON(mRow);

    ds_DetailInfo.setCellData(row, "cust", rowJson.cust);
    ds_DetailInfo.setCellData(row, "custnm", rowJson.custnm);
    ds_DetailInfo.setCellData(row, "contractno", rowJson.contractno);
    ds_DetailInfo.setCellData(row, "contractnoTamp", rowJson.contractno);
    ds_DetailInfo.setCellData(row, "liner", rowJson.liner);
    ds_DetailInfo.setCellData(row, "linernm", rowJson.linernm);
    ds_DetailInfo.setCellData(row, "portFrom", rowJson.portFrom);
    ds_DetailInfo.setCellData(row, "portFromNm", rowJson.portFromNm);
    ds_DetailInfo.setCellData(row, "portTo", rowJson.portTo);
    ds_DetailInfo.setCellData(row, "portToNm", rowJson.portToNm);
    ds_DetailInfo.setCellData(row, "apdtFrom", rowJson.apdtFrom);
    ds_DetailInfo.setCellData(row, "apdtTo", rowJson.apdtTo);
    ds_DetailInfo.setCellData(row, "kcomcd", "DBEX");
    ds_DetailInfo.setCellData(row, "blgb", "H");

    scwin.f_ContractInfo();
    scwin.f_Set("CREATE");

    ed_cust.focus();
};

scwin.f_ReqFieldChk = async function (workGb) {
    let vaildArray = [
        { id: "cust", name: "Customer", mandatory: true, length: 6 },
        { id: "contractno", name: "Contract No", mandatory: true, length: 11 },
        { id: "liner", name: "Liner Code", mandatory: false },
        { id: "portFrom", name: "Loading", mandatory: true, length: 5 },
        { id: "portTo", name: "Discharge", mandatory: true, length: 5 },
        { id: "apdtFrom", name: "From Date", mandatory: true, length: 8, valid: "date", format: "YYYYMMDD" },
        { id: "apdtTo", name: "To Date", mandatory: true, length: 8, valid: "date", format: "YYYYMMDD" },
        { id: "item", name: "Item", mandatory: false },
        { id: "fcode", name: "Freight", mandatory: true },
        { id: "type", name: "Type", mandatory: true },
        { id: "curr", name: "Currency", mandatory: true, length: 3 },
        { id: "amount", name: "Amount", mandatory: true, valid: "minNumber", minNumber: 1 },
        { id: "dg", name: "D/G", mandatory: true }
    ];

    switch (workGb) {
        case "SEARCH":
            let chk1 = await $c.gus.cfValidate(tb_searchCondition);

            if (!chk1) {
                return false;
            } else {
                return true;
            }
            break;
        case "DEATAIL_SEARCH":
            let chk2 = await $c.gus.cfValidate(tb_DetailInfo);
            let chk3 = await $c.gus.cfValidateGrid(gr_DetailInfo, null, null, vaildArray, "Tariff Information");

            if (!chk2 || !chk3) {
                return false;
            } else {
                return true;
            }
            break;
        case "TARIFFLIST":
            let chk4 = await $c.gus.cfValidateGrid(gr_TariffList, null, null, vaildArray, "Tariff");

            if (!chk4) {
                return false;
            } else {
                return true;
            }
            break;
    }
};

scwin.f_PopUp = function (pPopGubun, pWinCloseTF, pAllSearchTF, pNoDataCloseTF) {
    let pCode = "";
    let pName = "";

    switch (pPopGubun) {
        case "Customer_C":
            pCode = cnd_ed_cust.getValue().trim();
            pName = cnd_txt_custnm.getValue();

            udcCustomer1.ilCommonPopUp(scwin.callbackCustomerC,
                pCode, pName, pWinCloseTF, "2", "Customer Code,Customer Name,",
                "130,300", "3,4,5,6,7,8,9,10", null, "500", "500", null, null, null,
                pAllSearchTF, "Customer Search,Customer Code,Customer Name", "F");
            break;
        case "Loading_C":
            pCode = cnd_ed_portFrom.getValue().trim();
            pName = cnd_txt_portFromnm.getValue();

            udcLoading1.ilCommonPopUp(scwin.callbackLoadingC,
                pCode, pName, pWinCloseTF, "2", "Loading Code, Loading Name,",
                "130,300", "3,4,5,6,7,8,9,10", null, "500", "500", null, null, null,
                pAllSearchTF, "Loading Search,Loading Code,Loading Name", pNoDataCloseTF);
            break;
        case "Discharge_C":
            pCode = cnd_ed_portTo.getValue().trim();
            pName = cnd_txt_portTonm.getValue();

            udcDischarge1.ilCommonPopUp(scwin.callbackDischargeC,
                pCode, pName, pWinCloseTF, "2", "Discharge Code,Discharge Name,",
                "130,300", "3,4,5,6,7,8,9,10", null, "500", "500", null, null, null,
                pAllSearchTF, "Discharge Search,Discharge Code,Discharge Name", pNoDataCloseTF);
            break;
        case "Liner_C":
            pCode = cnd_ed_liner.getValue().trim();
            pName = cnd_txt_linernm.getValue();

            udcLiner1.ilCommonPopUp(scwin.callbackLinerC,
                pCode, pName, pWinCloseTF, "2", "Liner Code,Liner Name,",
                "130,300", "3,4,5,6,7,8,9,10", null, "500", "500", null, null, null,
                pAllSearchTF, "Liner Search,Liner Code,Liner Name", pNoDataCloseTF);
            break;
        case "Customer":
            pCode = ed_cust.getValue().trim();
            pName = txt_custnm.getValue();

            udcCustomer2.ilCommonPopUp(scwin.callbackCustomer,
                pCode, pName, pWinCloseTF, "2", "Customer Code,Customer Name,",
                "130,300", "3,4,5,6,7,8,9,10", null, "500", "500", null, null, null,
                pAllSearchTF, "Customer Search,Customer Code,Customer Name", pNoDataCloseTF);
            break;
        case "Loading":
            pCode = ed_portFrom.getValue().trim();
            pName = txt_portFromnm.getValue();

            udcLoading2.ilCommonPopUp(scwin.callbackLoading,
                pCode, pName, pWinCloseTF, "2", "Loading Code, Loading Name,",
                "130,300", "3,4,5,6,7,8,9,10", null, "500", "500", null, null, null,
                pAllSearchTF, "Loading Search,Loading Code,Loading Name", pNoDataCloseTF);
            break;
        case "Discharge":
            pCode = ed_portTo.getValue().trim();
            pName = txt_portTonm.getValue();

            udcDischarge2.ilCommonPopUp(scwin.callbackDischarge,
                pCode, pName, pWinCloseTF, "2", "Discharge Code,Discharge Name,",
                "130,300", "3,4,5,6,7,8,9,10", null, "500", "500", null, null, null,
                pAllSearchTF, "Discharge Search,Discharge Code,Discharge Name", pNoDataCloseTF);
            break;
        case "Liner":
            pCode = ed_liner.getValue().trim();
            pName = txt_linernm.getValue();

            udcLiner2.ilCommonPopUp(scwin.callbackLiner,
                pCode, pName, pWinCloseTF, "2", "Liner Code,Liner Name,",
                "130,300", "3,4,5,6,7,8,9,10", null, "500", "500", null, null, null,
                pAllSearchTF, "Liner Search,Liner Code,Liner Name", pNoDataCloseTF);
            break;
    }
};

scwin.callbackCustomerC = function (rtnList) {
    $c.gus.cfSetReturnValue(rtnList, cnd_ed_cust, cnd_txt_custnm);
};

scwin.callbackLoadingC = function (rtnList) {
    $c.gus.cfSetReturnValue(rtnList, cnd_ed_portFrom, cnd_txt_portFromnm);
};

scwin.callbackDischargeC = function (rtnList) {
    $c.gus.cfSetReturnValue(rtnList, cnd_ed_portTo, cnd_txt_portTonm);
};

scwin.callbackLinerC = function (rtnList) {
    $c.gus.cfSetReturnValue(rtnList, cnd_ed_liner, cnd_txt_linernm);
};

scwin.callbackCustomer = function (rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_cust, txt_custnm);

    if (typeof (rtnList) != "undefined") {
        if (rtnList[0].trim() != "N/A") {
            scwin.f_ContractInfo();
        }
    }
};

scwin.callbackLoading = function (rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_portFrom, txt_portFromnm);
};

scwin.callbackDischarge = function (rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_portTo, txt_portTonm);
};

scwin.callbackLiner = function (rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_liner, txt_linernm);
};

scwin.f_PopUpGrid = function (disGubun, row, pWinCloseTF, pAllSearchTF) {
    let rowJson = ds_DetailInfo.getRowJSON(row);
    let pCode = "";
    let pName = "";

    switch (disGubun) {
        case "Customer":
            pCode = rowJson.cust;
            pName = "";

            udcGridCustomer.ilCommonPopUp(function (rtnList) {
                $c.gus.cfSetGridReturnValue(rtnList, ds_DetailInfo, row, "cust", "", [""]);
            }, pCode, pName, pWinCloseTF, "2", "Customer Code,Customer Name,",
                "130,300", "3,4,5,6,7,8,9,10", null, "500", "500", null, null, null,
                pAllSearchTF, "Customer Search,Customer Code,Customer Name", "F");
            break;
        case "Liner":
            udcGridLiner.ilCommonPopUp(function (rtnList) {
                $c.gus.cfSetGridReturnValue(rtnList, ds_DetailInfo, row, "liner", "", [""]);
            }, ds_DetailInfo.getCellData(row, "liner"), "", pWinCloseTF, "2", "Liner Code,Liner Name,",
                "130,300", "3,4,5,6,7,8,9,10", null, "500", "500", null, null, null,
                pAllSearchTF, "Liner Search,Liner Code,Liner Name", "F");
            break;
        case "Loading":
            udcGridLoading.ilCommonPopUp(function (rtnList) {
                $c.gus.cfSetGridReturnValue(rtnList, ds_DetailInfo, row, "portFrom", "", [""]);
            }, ds_DetailInfo.getCellData(row, "portFrom"), "", pWinCloseTF, "2", "Loading Code,Loading Name,",
                "130,300", "3,4,5,6,7,8,9,10", null, "500", "500", null, null, null,
                pAllSearchTF, "Loading Search,Loading Code,Loading Name", "F");
            break;
        case "Discharge":
            udcGridDischarge.ilCommonPopUp(function (rtnList) {
                $c.gus.cfSetGridReturnValue(rtnList, ds_DetailInfo, row, "portTo", "", [""]);
            }, ds_DetailInfo.getCellData(row, "portTo"), "", pWinCloseTF, "2", "Discharge Code,Discharge Name,",
                "130,300", "3,4,5,6,7,8,9,10", null, "500", "500", null, null, null,
                pAllSearchTF, "Discharge Search,Discharge Code,Discharge Name", "F");
            break;
        case "Item":
            udcGridItem.ilCommonPopUp(function (rtnList) {
                $c.gus.cfSetGridReturnValue(rtnList, ds_DetailInfo, row, "item", "itemnm", [""]);
            }, ds_DetailInfo.getCellData(row, "item"), "", pWinCloseTF, "2", "Item Code,Item Name,",
                "130,300", "3,4,5,6,7,8,9,10", null, "500", "500", null, null, null,
                pAllSearchTF, "Item Search,Item Code,Item Name", "F");
            break;
        case "Freight":
            let arry = ["", "selpchItemCd", "", "", "", "", "", ""];

            udcGridFreight.ilCommonPopUp(function (rtnList) {
                $c.gus.cfSetGridReturnValue(rtnList, ds_DetailInfo, row, "fcode", "fcodenm", arry);
            }, ds_DetailInfo.getCellData(row, "fcode"), "", pWinCloseTF, "2", "Freight Code, Freight Name,",
                "130,300", "3,4,5,6,7,8,9,10", "S", "500", "500", null, null, null,
                pAllSearchTF, "Freight Search,Freight Code,Freight Name", "F");
            break;
        case "CNTR_TYPE":
            udcGridCNTR_TYPE.ilCommonPopUp(function (rtnList) {
                $c.gus.cfSetGridReturnValue(rtnList, ds_DetailInfo, row, "type", "typenm", [""]);
            }, ds_DetailInfo.getCellData(row, "type"), "", pWinCloseTF, "10", "Container Code, Container Name,",
