            break;
    }
};

//-------------------------------------------------------------------------
// function	name : f_BeforePopUpEd
// function	desc : 공통팝업 열기 전에 체크- EMEDIT onKillFocus 이벤트	발생시
//					nmObj-코드명(text),	cdObj-코드(emedit),	gubun1
//-------------------------------------------------------------------------
scwin.f_BeforePopUpEd = function (nmObj, cdObj, gubun1, pWinCloseTF, pAllSearchTF) {
    let cdObjVal = cdObj.getValue().trim();

    if (cdObjVal.originalValue != cdObjVal) {
        if (cdObjVal == "") {
            nmObj.setValue("");
        } else {
            nmObj.setValue("");
            scwin.f_PopUp(gubun1, pWinCloseTF, pAllSearchTF);
        }
    }
};

//-------------------------------------------------------------------------
// function	name : f_ChkPopUp
// function	desc : 팝업	처리시 검색된 데이터인 경우	팝업 처리 안함.
//------------------------------------------------------------------------
scwin.f_ChkPopUp = function (data, disGubun, isCode) {
    if (isCode == null || isCode == true) {
        scwin.f_PopUp(disGubun, "T", "T", "F");
    } else {
        scwin.f_PopUp(disGubun, "T", "T", "F");
    }
};

//-------------------------------------------------------------------------
// function	name : f_DownExcelSheet
// function	desc : 엑셀저장
//-------------------------------------------------------------------------
scwin.f_DownExcelSheet = async function () {
    if (ds_DetailInfo.getRowCount() != 0) {
        let cfrm = await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?");

        if (cfrm) {
            let arg = await $c.win.confirm(" [Yes] SAVE To CSV \n [No] Grid To Excel");

            if (arg) {
                $c.data.downloadGridViewCSV(gr_DetailInfo, {
                    fileName: "ContainerSellingTariff.csv",
                    sheetName: "ContainerSellingTariff",
                    hidden: "1",
                    hiddenVisible: true,
                    removeQuotation: "0"
                });
            } else {
                $c.data.downloadGridViewExcel(gr_DetailInfo, {
                    fileName: "ContainerSellingTariff.xlsx",
                    sheetName: "ContainerSellingTariff",
                    hidden: "1",
                    hiddenVisible: true,
                    removeQuotation: "0"
                });
            }
        }
    } else {
        $c.gus.cfAlertMsg(E_MSG_CM_WRN_002);
    }
};

