// function desc : Excel등록
//-------------------------------------------------------------------------
scwin.f_ExcelUp = async function () {
    if (scwin.statusFlag != "CREATE") {
        await $c.win.alert("신규모드에서 실행 가능합니다.");
        return;
    }

    ds_DetailInfo.setJSON([]);

    if (udc_topGrd.getUpExt() == "1") { // xlsx, csv 선택값
        let options = {
            "fileName": "ContainerSellingTariff(Customer).csv",
            "status": "C",
            "header": 1,
            "type": "1",
            "hidden": "1"
        };

        $c.data.uploadGridViewCSV(gr_DetailInfo, options); // CSV를 선택하였을 경우
    } else {
        let options = {
            "fileName": "ContainerSellingTariff(Customer).xslx",
            "status": "C",
            "header": 1,
            "type": "1",
            "hidden": "1",
            "startRowIndex": 2
        };

        $c.data.uploadGridViewExcel(gr_DetailInfo, options); // XLSX를 선택하였을 경우
    }
};

