    scwin.ctrtNoRowCount = 0;

    ds_ctrtNoIsNull.setJSON([]);
    dma_retrieveCtrtClnt.setEmptyValue();

    dma_retrieveCtrtClnt.set("ctrtClntNo", custCd);
    dma_retrieveCtrtClnt.set("bizDivCntrYn", "1");
    dma_retrieveCtrtClnt.set("ctrtDistrictCd", "ZZA");
    dma_retrieveCtrtClnt.set("ctrtNo", contractNo);

    $c.sbm.execute(sbm_retrieveCtrtClntVaildation);
};

