    ds_ctrtNo.setJSON([]);
    dma_retrieveCtrtClnt.setEmptyValue();

    dma_retrieveCtrtClnt.set("ctrtClntNo", ds_DetailInfo.getCellData(ds_DetailInfo.getRowPosition() || 0, "cust"));
