//-------------------------------------------------------------------------
// function	name : f_OpenPgm
// function	desc : 기능버튼 화면 이동
//-------------------------------------------------------------------------
scwin.f_OpenPgm = async function (name) {
    await $c.win.alert("개발중입니다.");
    return;
};

scwin.sbm_retrieve_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

    let rowCount = ds_MasterList.getRowCount();

    if (rowCount == 0) {
        await $c.gus.cfAlertMsg(E_MSG_CM_WRN_002);
        scwin.f_Set("INIT");
    } else {
        for (let i = 0; i < rowCount; i++) {
            ds_MasterList.setCellData(i, "Currow", i + 1);
        }

        ds_MasterList.initRowStatus();
        ds_MasterList.setRowPosition(0);
    }

    totalRows1.setValue(rowCount);
};

scwin.sbm_retrieveCtrtClntVaildation_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

    let rowCount = ds_ctrtNoIsNull.getRowCount();

    if (rowCount == 0) {
        scwin.ctrtNoRowCount = rowCount;
    }
};

scwin.sbm_retrieve_info_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

    await scwin.f_Set("SAVE");

    let rowCount = ds_DetailInfo.getRowCount();

    if (rowCount == 0) {
        await $c.gus.cfAlertMsg(E_MSG_CM_WRN_002);
        scwin.f_Set("INIT");
    } else {
        for (let i = 0; i < rowCount; i++) {
            ds_DetailInfo.setCellData(i, "Currow", i + 1);
        }

        ds_DetailInfo.modifyAllStatus("R");

        await scwin.f_ContractInfo();

        ds_DetailInfo.setRowPosition(rowCount - 1);
    }

    gr_DetailInfo.setColumnReadOnly("item", true);
    gr_DetailInfo.setColumnReadOnly("fcode", true);
    gr_DetailInfo.setColumnReadOnly("curr", true);
    gr_DetailInfo.setColumnReadOnly("type", true);

    totalRows2.setValue(rowCount);
};

scwin.sbm_retrieve_list_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

    await scwin.f_Set("SAVE");

    let rowCount = ds_TariffList.getRowCount();

    if (rowCount == 0) {
        await $c.gus.cfAlertMsg(E_MSG_CM_WRN_002);
        scwin.f_Set("INIT");
    } else {
        for (let i = 0; i < rowCount; i++) {
            ds_TariffList.setCellData(i, "Currow", i + 1);
        }

        ds_TariffList.initRowStatus();
    }

    totalRows3.setValue(rowCount);
};

scwin.sbm_save_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

    await $c.gus.cfAlertMsg(E_MSG_CM_INF_001);
    scwin.f_Retrieve();
};

scwin.sbm_save_list_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

    await $c.gus.cfAlertMsg(E_MSG_CM_INF_001);
    scwin.f_Retrieve();
};

scwin.ds_MasterList_onrowpositionchange = async function (e) {
    if (!scwin.flag) {
        return;
    }

    if (ds_DetailInfo.getModifiedIndex().length > 0) {
        let chk = await $c.win.confirm("There have been changes in Tariff.<br/>Please save first and try again.");

        if (chk) {
            scwin.flag = false;
            ds_MasterList.setRowPosition(e.oldRowIndex, false);
            scwin.flag = true;
            return;
        }
    }

    let row = ds_MasterList.getRowPosition();

    if (row == null) return;

    if (row >= 0) {
        scwin.preRowPos = row;
        scwin.f_DetailInfoRetrieve(row);
        scwin.f_Set("RETRIEVE_D");
    }
};

scwin.ds_DetailInfo_onrowpositionchange = function (e) {
    let row = ds_DetailInfo.getRowPosition();

    scwin.f_ContractInfo();

    if (ds_DetailInfo.getRowStatus(row) == "C") {
        gr_DetailInfo.setColumnReadOnly("item", false);
        gr_DetailInfo.setColumnReadOnly("fcode", false);
        gr_DetailInfo.setColumnReadOnly("curr", false);
        gr_DetailInfo.setColumnReadOnly("type", false);
    } else {
        gr_DetailInfo.setColumnReadOnly("item", true);
        gr_DetailInfo.setColumnReadOnly("fcode", true);
        gr_DetailInfo.setColumnReadOnly("curr", true);
        gr_DetailInfo.setColumnReadOnly("type", true);
    }
};

