};

scwin.sbm_retrieveCtrtClnt_submitdone = function (e) {
    for (let i = 0; i < ds_ctrtNo.getRowCount(); i++) {
        let rowJson = ds_ctrtNo.getRowJSON(i);

        ds_ctrtNo.setCellData(i, "label", rowJson.ctrtNo + " (" + rowJson.clntPicNm + ":~" + rowJson.ctrtEndDt + ":" + rowJson.crcCd + ")");
    }
};
